var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……하.","JPN":"……は。","ENG":"*...Sigh*","TWN":"……哈。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이건 예상에 없어서 더 당황스럽네. 그동안 내 뒤꽁무니를 쫓는 것만으로는 부족했어?","JPN":"予想外のことすぎて対応に困るわね。私の後をつけるだけじゃ足りなかったの？","ENG":"Didn't see this one coming. Was tailing me around not enough for you?","TWN":"這真是出乎意料，讓我更加慌亂。難道之前只是跟在我後面還不夠嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"몇 번이나 만나러 갔는데 만남을 거부한 건 경이 아니십니까.","JPN":"何度も会いに行ったのに拒んだのはあなたではありませんか。","ENG":"I tried to meet you several times. You're the one who refused every time, weren't you?","TWN":"我去見了好幾次，但拒絕見面的不是你嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"가문의 기사들에게 들었어. 버고 소드를 놔두고 돌연 자취를 감췄다면서?","JPN":"家の騎士たちから聞いたわ。ヴァルゴソードを置いて突然姿を消したんだって？","ENG":"I heard from your knights. You left the Virgo Sword behind and just disappeared?","TWN":"我聽家族的騎士們說了。你突然消失了，留下布林加夫之劍不管不顧？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"우리 아가씨에게 무슨 바람이 분 걸까? 오빠 흉내를 내니 그런 것까지 따라하고 싶었어?","JPN":"どういう風の吹き回しかしら？　そんなところまでお兄さんの真似がしたかった？","ENG":"What's gotten into our little lady? Playing copycat with your brother now, too?","TWN":"你是受了什麼風的影響嗎？模仿哥哥連這種事情都想學嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아니면, 가출이라도 하니 집이 그리워졌어? 내 지지를 얻어 단장 자리라도 되찾으려고?","JPN":"それとも、家出したら家が恋しくなった？　私の支持を得て、団長の座を取り戻すつもり？","ENG":"Or what, ran away from home and now you're homesick? Hoping to win my favor and reclaim your title?","TWN":"還是說，你離家出走了，現在想家了？想要得到我的支持，重新奪回團長的位置嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"메데이아 경이 그러더군요. 전임 기사단장은 책임을 저버릴 사람이 아니라고.","JPN":"メデイア卿から聞きました。前騎士団長は責任を放棄するような人間ではないと。","ENG":"Dame Medea told me... the former captain was not the kind of man to abandon his duty.","TWN":"美狄亞這麼說過。前任騎士團團長不是一個會逃避責任的人。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 진실을 알기 위해 찾아왔습니다, 레온하르트 경.","JPN":"私は真実を知るために来たんです、レオンハルト卿。","ENG":"I came to find the truth, Dame Leonhardt.","TWN":"我來是為了尋找真相，里恩哈特。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오빠가 버고 소드를 내려놓고… 레드시프트의 행방을 찾아 떠난 그 날의 진실을요.","JPN":"兄がヴァルゴソードを手放し……レッドシフトの行方を探しに出たあの日の真実を。","ENG":"The truth behind the day my brother gave up the Virgo Sword... and left to find Red Shift.","TWN":"哥哥放下了布林加夫之劍……去尋找紅移下落的那天的真相。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…그 망할 계집. 쓸데없는 소리 떠벌리고 다니긴.","JPN":"……あの女。余計なこと言いやがって。","ENG":"...That damn girl. Running her mouth again where she shouldn't.","TWN":"……那個該死的。到處說些廢話。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"좋아. 네 오빠에 대해 궁금하다면 알려주지, 뭐.","JPN":"そう。あなたのお兄さんについてそんなに知りたいなら、教えてあげてもいいわよ。","ENG":"Fine. If you're so curious about your brother, I'll tell you.","TWN":"好吧。如果你對你哥哥感興趣，我可以告訴你一些事情。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그게 정말이십니까?","JPN":"本当ですか？","ENG":"You really mean it?","TWN":"你說的是真的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래~. 네 오빠는 말이지~.","JPN":"ええ～。あなたのお兄さんはね～","ENG":"Sure. Your brother, well...","TWN":"是啊～你哥哥就是這樣～"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"단장의 책임을 등한시하다 버고 소드에게 버림받은 걸 인정하지 못하고 도망쳤어.","JPN":"団長の責任を疎かにしてヴァルゴソードに捨てられたことが受け入れられず、逃げたの。","ENG":"He ran away because he couldn't accept that the Virgo Sword had abandoned him for failing his duties.","TWN":"因為忽視團長的責任，被布林加夫之劍拋棄，卻無法承認這一點而逃跑了。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"레드시프트를 찾아 떠났다는 건 형편 좋은 변명이지.","JPN":"レッドシフトを探すなんて、都合のいい口実だったわ。","ENG":"That story about searching for Red Shift? Just a pretty excuse.","TWN":"說是去尋找紅移，不過是個不錯的藉口罷了。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"표정이 왜 그래? 혹시 네 오빠가 세상을 구하다 죽은 영웅이라도 되는 줄 아니?","JPN":"何その顔？　もしかして、お兄さんは世界を救おうとして死んだ英雄だとでも思ってた？","ENG":"Why the face? Did you think he was some fallen hero who died saving the world?","TWN":"表情怎麼這樣？難道你以為你哥哥是拯救世界而犧牲的英雄嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"정신 차려, 아가씨. 기사단이 말하는 <color=#ffd34c>정의</color>는 전부 허상이야.","JPN":"目を覚ましなさい、お嬢さん。騎士団の言う<color=#ffd34c>正義</color>は全部虚像よ。","ENG":"Wake up, girl. That <color=#ffd34c>justice</color> the knights go on about? It's all just a fantasy.","TWN":"清醒點，小姐。騎士團所說的<color=#ffd34c>正義</color>全都是虛幻的。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"혹시 정의로움이 세상을 바꿀 수 있다고 믿는 정신병자들이 있다면…….","JPN":"正義で世界を変えられるなんてほざく狂人がいるなら……","ENG":"If there really are lunatics who think justice can save the world...","TWN":"如果說有些精神病患者能用正義改變世界的話……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그런 놈들. 엿이나 먹으라지. 꽃밭인 머리로 눈 가리고 아웅하는 것도 지겨우니까.","JPN":"くそくらえだ。脳みそお花畑で、現実から目を逸らすのもいい加減にしなさいっての。","ENG":"They can go choke on it. I'm sick of all that starry-eyed, make-believe crap.","TWN":"那些傢伙。讓他們去死吧。整天腦子裡裝這些荒唐的想法都夠煩了。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"왜… 그런 소리를 하는 거죠?","JPN":"なぜ……そんなことを言うのですか？","ENG":"Why... would you say something like that?","TWN":"為什麼……要說那種話呢？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"적어도 당신만큼은 그런 소리를 하면 안 되는 게 아닙니까?","JPN":"少なくともあなただけは、そう言ってはいけないのではありませんか？","ENG":"You, of all people shouldn't be the one saying it.","TWN":"至少你不應該說這種話吧？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신은, 전임 기사단장 시절……!","JPN":"あなたは、前騎士団長の頃……！","ENG":"You were captain once...!","TWN":"你是，前任騎士團長時期……！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"옛날 일로 질척거리지 마. 지금 블루시프트의 부단장은 피오네잖니?","JPN":"昔のことで付きまとわないで。今ブルーシフトの副団長はフィオネよ？","ENG":"Spare me the nostalgia. The deputy of Blue Shift now is Fione, isn't it?","TWN":"別糾結於過去的事情了。現在藍移的副團長是菲奧尼吧？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"네가 없다고 아등바등하는 모양인데… 안 되지. 피오네는 재능이 없거든.","JPN":"あなたの不在で苦労してるみたいだけど……ダメね。フィオネには才能がないもの。","ENG":"Seems like she's struggling now that you're gone... Poor thing. Not much talent, that one.","TWN":"看來你不在的時候他們都手忙腳亂的……不行啊。因為菲奧尼沒有天賦。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"당장 건틀렛에서 카운터도 아닌 애 상대로 애먹는 걸 보면 그동안 어지간히 놀았나 봐?","JPN":"ガントレットでカウンターでもない子相手に手こずってるわけだし、今まで遊んでばかりいたようね？","ENG":"Struggling in the Gauntlet against someone who's not even a Counter? Looks like she's been slacking off.","TWN":"看你在聖鎧中對付一個非制裁者都這麼吃力，看來你之前真是玩得太過了吧？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……그 말. 취소하시죠.","JPN":"……その発言、撤回してください。","ENG":"...You take that back.","TWN":"……那句話，請收回吧。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 몰라도 그녀는 별의 부름을 받은 정의로운 기사입니다.","JPN":"私はともかく、彼女は星に呼ばれた正義の騎士です。","ENG":"Say what you want about me, but she's a righteous knight, chosen by the stars.","TWN":"說我就算了，但她是受到星辰召喚的正義騎士。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래, 취소. 피오네뿐만 아니라 현 블루시프트 전원이 쓰레기야.","JPN":"はいはい、撤回。フィオネだけじゃなくて、今のブルーシフトは全員がカス。","ENG":"Sure, fine. I take it back. Not just her, the whole Blue Shift squad is trash now.","TWN":"是的，取消。不僅是菲奧尼，現在整個藍移都是垃圾。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"기사 같은 건 때려 치고, 이참에 단체로 광대놀음이라도 하는 게 어때?","JPN":"騎士なんてやめて、皆でサーカスでもやったらどう？","ENG":"Forget knighthood. Why don't they go start a clown act together?","TWN":"騎士什麼的都放棄吧，趁這個機會一起去當小丑怎麼樣？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신…!!","JPN":"あなた……！！","ENG":"You...!","TWN":"你……！！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"크윽!!","JPN":"くっ！！","ENG":"Kgh!!","TWN":"呃！！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_START_1"},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"미련한 건지 멍청한 건지. 무구도 없이 내 상대가 될 것 같아?","JPN":"未熟なのかバカなのか。武具もないのに私の相手ができるとでも思った？","ENG":"What, did you think you could take me on without your Armament? I can't tell if you're foolish or just stupid.","TWN":"是愚蠢還是傻呢？沒有武器就想和我對抗嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래도 감정적으로 변한 건 마음에 드네. 오랜만에 네 예전 모습 보는 것 같았어.","JPN":"でも、感情的になったのは気に入ったわ。久しぶりに昔のあなたに会えた気がして。","ENG":"Still, I liked seeing you lose your temper. It's been a while since I've seen the old you.","TWN":"不過我喜歡你變得感性。感覺好久沒看到你以前的樣子了。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오지만… 디아스……!!","JPN":"オジマン……ディアス……！！","ENG":"Ozyman... dias...!","TWN":"奧茲曼……迪亞斯……！！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어~ 그래. 나 오지만디아스야.","JPN":"はいはい、オジマンディアスですよ。","ENG":"Yeah, that's me. Ozymandias.","TWN":"喔～對，我是奧茲曼迪亞斯。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"줄리아 레온하르트는 옛날 옛적에 죽었어. 소꿉놀이를 하려거든 네 잘난 동료들이랑 해.","JPN":"ジュリア・レオンハルトはとっくの昔に死んだ。おままごとがしたいなら、あなたの大切な仲間とやりなさい。","ENG":"Julia Leonhardt died a long time ago. If you want to play house, go do it with your precious friends.","TWN":"茱莉亞·里恩哈特早已死去。如果想玩過家家，就和你那些自以為是的同伴一起玩吧。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"알아들었으면 꺼져. 내가 알려줄 건 아무것도 없으니까.","JPN":"わかったなら失せて。私があなたに教えられることは何もないから。","ENG":"If you've got nothing else, then scram. I've got nothing more to say.","TWN":"聽懂了就滾吧。我沒什麼好告訴你的。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……당신이 무슨 말을 하든, 난 오빠를 믿어.","JPN":"……あなたが何と言おうと、私は兄のことを信じる。","ENG":"...No matter what you say, I still believe in my brother.","TWN":"……無論你說什麼，我都相信哥哥。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"믿던가 말던가. 네 맘대로 하렴~.","JPN":"信じるも何も、好きにすれば～","ENG":"Believe what you want. See if I care.","TWN":"信不信由你。隨你便～"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오빠를 믿으니까… 기사단을 떠난 뒤 당신을 만나려 했던 거야.","JPN":"兄を信じたから……騎士団を離れて、あなたに会おうと思った。","ENG":"Because I believe in him... I came to you after leaving the Order.","TWN":"因為我相信哥哥……所以離開騎士團後想要見你。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오빠는, <color=#ffd34c>줄리아 언니</color>를 믿을 수 있는 사람이라 말했으니까.","JPN":"兄は、<color=#ffd34c>ジュリアさん</color>は信用できる人だと言っていたから。","ENG":"He once told me that <color=#ffd34c>Julia</color> is someone I could trust.","TWN":"哥哥說，<color=#ffd34c>茱莉亞姊姊</color>是可以信任的人。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"알게 뭐람. 그딴 거.","JPN":"そんなの、私の知ったことじゃないわ。","ENG":"So what? Who cares.","TWN":"關我什麼事。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"지금 거신 전화는 없는 번호입니다. 다시 확인하고 걸어주세요~.","JPN":"おかけになった番号は、現在使われておりません。番号をお確かめになっておかけ直しください～","ENG":"The number you have dialed is not in service. Please check the number and try again.","TWN":"你撥打的電話是空號。請稍後再撥～"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"번호 안 바꾼 거 알아. 장난치지 마.","JPN":"番号変わってないの知ってるわよ。ふざけないで。","ENG":"I know you didn't change your number. Don't screw with me.","TWN":"我知道你沒換號碼。別開玩笑了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그럴 눈치가 있으면 내가 전화 받기 싫어하는 것도 눈치채야 하는 거 아냐?","JPN":"それがわかるなら、電話に出たくない私の気持ちもわかるんじゃない？","ENG":"If you've got that much awareness, maybe you should realize I don't want to take your calls?","TWN":"如果你有這樣的聰明，就應該察覺到我不想接電話吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"평소에는 연락 한번 없으면서, 매번 귀찮은 일이 생겼을 때만 나를 찾더라?","JPN":"いつもは全然連絡してこないくせに、厄介事になるといつも私に頼るのね。","ENG":"Never heard from you until you've got a mess on your hands. Every time, it's the same thing.","TWN":"平時不聯絡我，每次只有麻煩事的時候才找我？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"귀찮은 일이니까 귀찮은 년을 찾지. 그럼 애먼 사람한테 화풀이하니?","JPN":"厄介事だから厄介なやつを頼るのよ。関係ない人に八つ当たりするわけにはいかないでしょう？","ENG":"And when it's a mess, I call the annoying girl. What, should I go dump it on someone innocent instead?","TWN":"麻煩的事情就找個麻煩的女人去做。那你就不會無緣無故地對別人發火了吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"네~. 그 말 그대로 돌려드릴게요~.","JPN":"はいはい、その言葉、そのままお返ししますわ～","ENG":"Sure. I'll say that right back at you!","TWN":"是～那句話，我原封不動地還給你～"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"더럽게 귀찮게 구네. 대체 무슨 일인데?","JPN":"本当に面倒くさいわね。それで、いったい何の用？","ENG":"You're such a pain. What do you want?","TWN":"真是煩人。到底有什麼事？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너, 에스텔한테 무슨 말을 한 거야.","JPN":"あなた、エステルに何を言ったの？","ENG":"What did you tell Esther?","TWN":"你對艾斯特說了什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어머~. 둘이 만났어? 잘 됐다~.","JPN":"あら、会えたの？　よかったわね～","ENG":"Oh my! So you two finally met? That's great!","TWN":"哎呀～你們見面了？太好了～"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아…… 아니, 됐다.","JPN":"はあ……もういい。","ENG":"*Sigh...* Forget it.","TWN":"哈……算了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"지금까지 무슨 일이 있었는지 말해.","JPN":"今まで何があったか、教えなさい。","ENG":"Just tell me what happened. All of it.","TWN":"至今為止發生了什麼事，說吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하나도 남김없이, 전부 다.","JPN":"残らず、全部。","ENG":"Every last detail. And don't leave anything out.","TWN":"一個不留，全部。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};